public class Student {
    String name;
    int age;

    Student(String name, int age) {
        this.name = name; // this.name = the FIELD, name = the PARAMETER
        this.age = age;
    }
}

public class Student {
    String name;
    int age;

    Student(String studentName, int studentAge) {
        name = studentName; // no clash -- this. is optional here
        age = studentAge;
    }
}

public class Main {
    static class Counter {
        int count;

        void increment() {
            this.count = this.count + 1;
        }
    }

    public static void main(String[] args) {
        Counter c = new Counter();
        c.increment();
        c.increment();
        System.out.println(c.count);
    }
}

public class Student {
    String name;
    int age;

    Student(String name, int age) {
        this.name = name;
        this.age = age;
    }

    Student(String name) {
        this(name, 18); // calls the two-argument constructor above
    }
}

public class Main {
    public static void main(String[] args) {
        Student s = new Student("Aman");
        System.out.println(s.name + " is " + s.age);
    }
}

